mapper.select:
SELECT oi.*, COALESCE(p.name, oi.product_name_snapshot, CONCAT('#', oi.product_id)) as product_name, COALESCE(NULLIF(p.image_url, ''), NULLIF(oi.image_url_snapshot, '')) as image_url FROM order_items oi LEFT JOIN products p ON oi.product_id = p.id WHERE oi.order_id IN
#{orderId}
ORDER BY oi.order_id ASC, oi.id ASC

SELECT oi.product_id AS productId, COALESCE(MAX(p.name), MAX(oi.product_name_snapshot), CONCAT('#', oi.product_id)) AS productName, COALESCE(MAX(NULLIF(p.image_url, '')), MAX(NULLIF(oi.image_url_snapshot, ''))) AS imageUrl, COALESCE(SUM(oi.quantity), 0) AS quantity, COALESCE(SUM(oi.price * oi.quantity), 0) AS revenue FROM order_items oi INNER JOIN orders o ON o.id = oi.order_id LEFT JOIN products p ON oi.product_id = p.id WHERE oi.product_id IS NOT NULL AND o.status IN
#{status}
GROUP BY oi.product_id ORDER BY revenue DESC, quantity DESC, productId DESC LIMIT #{limit}
